beforeExample:
import org.eclipse.jdt.core.dom.IMethodBinding;
import java.lang.reflect.Modifier;

class QuickAssistProcessor {
    void processMethod(IMethodBinding referredMethodBinding) {
        // Before (part of an else if condition)
        if (false) {} else if (Modifier.isStatic(referredMethodBinding.getModifiers()) && !referredMethodBinding.isSynthetic()) {
            System.out.println("Condition matched: static and not synthetic");
        }
    }
}

afterExample:
import org.eclipse.jdt.core.dom.IMethodBinding;
import java.lang.reflect.Modifier;

class QuickAssistProcessor {
    void processMethod(IMethodBinding referredMethodBinding) {
        // After
        if (false) {} else if (referredMethodBinding != null && Modifier.isStatic(referredMethodBinding.getModifiers())) {
            System.out.println("Condition matched: static");
        }
    }
}

negativeExample:
import org.eclipse.jdt.core.dom.IMethodBinding;
import java.lang.reflect.Modifier;

class QuickAssistProcessor {
    void processMethod(IMethodBinding referredMethodBinding) {
        // Not matching because it's only checking static
        if (Modifier.isStatic(referredMethodBinding.getModifiers())) {
            System.out.println("Only static check");
        }
        // Not matching because it's only checking synthetic
        if (referredMethodBinding.isSynthetic()) {
            System.out.println("Only synthetic check");
        }
        // Not matching because it's missing '!' for synthetic
        if (Modifier.isStatic(referredMethodBinding.getModifiers()) && referredMethodBinding.isSynthetic()) {
            System.out.println("Static and synthetic");
        }
    }
}
